-- Reconstruction SQL: Attach local databases and create views
-- that reconstruct the original tables.

ATTACH DATABASE 'local_1.sqlite' AS "local_1";
ATTACH DATABASE 'local_2.sqlite' AS "local_2";
ATTACH DATABASE 'local_3.sqlite' AS "local_3";

-- Reconstruct case_ids from local_1.CaseRegistry
CREATE VIEW "case_ids" AS
SELECT
    "local_1"."CaseRegistry"."CaseIdentifier" AS "case_id",
    "local_1"."CaseRegistry"."DatabaseYear" AS "db_year"
FROM "local_1"."CaseRegistry";

-- Reconstruct collisions from vertical split + row partition on a fragment
CREATE VIEW "collisions" AS
SELECT t0.[incident_id], t1.[jurisdiction_id], t2.[reporting_officer_id], t1.[reporting_district_code], t1.[chp_shift_designation], t3.[population_size], t1.[county_city_location_code], t3.[county_location_name], t3.[special_condition_flag], t1.[beat_category], t1.[chp_beat_category], t1.[lapd_city_division_name], t1.[chp_beat_classification], t1.[beat_designator], t3.[primary_road_name], t3.[secondary_road_name], t0.[collision_distance], t3.[travel_direction], t0.[intersection_location_flag], t3.[weather_primary], t3.[weather_secondary], t3.[state_highway_indicator_flag], t1.[caltrans_county_name], t1.[caltrans_district_code], t3.[state_route_number], t3.[route_suffix_code], t3.[postmile_prefix_code], t3.[postmile_value], t4.[location_type_description], t4.[ramp_intersection_description], t3.[highway_side], t0.[tow_away_flag], t2.[severity_level], t2.[fatality_total], t2.[injured_victim_total], t2.[involved_party_count], t0.[primary_collision_factor_text], t0.[violation_code], t0.[violation_category], t0.[pcf_violation_flag], t0.[violation_subsection], t3.[hit_and_run_flag], t4.[collision_type], t0.[other_vehicle_involved_description], t3.[pedestrian_action_description], t3.[road_surface_type], t3.[road_condition_primary], t3.[road_condition_secondary], t3.[lighting_conditions], t3.[control_device_type], t1.[chp_road_class], t0.[pedestrian_collision_flag], t0.[bicycle_collision_flag], t0.[motorcycle_collision_flag], t0.[truck_collision_flag], t3.[public_property_flag], t0.[alcohol_influence], t1.[statewide_at_fault_vehicle_type], t1.[chp_at_fault_vehicle_type], t2.[severe_injury_total], t2.[visible_injury_other_count], t2.[pain_complaint_count], t2.[pedestrian_fatalities_count], t2.[pedestrian_injury_count], t2.[bicyclist_fatalities_count], t2.[bicyclist_injury_count], t2.[motorcyclist_fatalities_count], t2.[motorcyclist_injury_count], t4.[primary_ramp_name], t4.[secondary_ramp_name], t3.[geo_latitude], t3.[geo_longitude], t3.[occurrence_date], t3.[occurrence_time], t3.[record_process_date]
FROM [local_2].[crash_alcohol_details] t0
JOIN (
SELECT [crash_beat_known_list].[__orig_rowid] AS __orig_rowid, [local_2].[crash_beat_known_list].[incident_id], [local_2].[crash_beat_known_list].[jurisdiction_id], [local_2].[crash_beat_known_list].[reporting_district_code], [local_2].[crash_beat_known_list].[chp_shift_designation], [local_2].[crash_beat_known_list].[county_city_location_code], [local_2].[crash_beat_known_list].[beat_category], [local_2].[crash_beat_known_list].[chp_beat_category], [local_2].[crash_beat_known_list].[lapd_city_division_name], [local_2].[crash_beat_known_list].[chp_beat_classification], [local_2].[crash_beat_known_list].[beat_designator], [local_2].[crash_beat_known_list].[caltrans_county_name], [local_2].[crash_beat_known_list].[caltrans_district_code], [local_2].[crash_beat_known_list].[chp_road_class], [local_2].[crash_beat_known_list].[statewide_at_fault_vehicle_type], [local_2].[crash_beat_known_list].[chp_at_fault_vehicle_type] FROM [local_2].[crash_beat_known_list]
UNION
SELECT [crash_beat_other_bucket].[__orig_rowid] AS __orig_rowid, [local_2].[crash_beat_other_bucket].[incident_id], [local_2].[crash_beat_other_bucket].[jurisdiction_id], [local_2].[crash_beat_other_bucket].[reporting_district_code], [local_2].[crash_beat_other_bucket].[chp_shift_designation], [local_2].[crash_beat_other_bucket].[county_city_location_code], [local_2].[crash_beat_other_bucket].[beat_category], [local_2].[crash_beat_other_bucket].[chp_beat_category], [local_2].[crash_beat_other_bucket].[lapd_city_division_name], [local_2].[crash_beat_other_bucket].[chp_beat_classification], [local_2].[crash_beat_other_bucket].[beat_designator], [local_2].[crash_beat_other_bucket].[caltrans_county_name], [local_2].[crash_beat_other_bucket].[caltrans_district_code], [local_2].[crash_beat_other_bucket].[chp_road_class], [local_2].[crash_beat_other_bucket].[statewide_at_fault_vehicle_type], [local_2].[crash_beat_other_bucket].[chp_at_fault_vehicle_type] FROM [local_2].[crash_beat_other_bucket]
) t1 ON t0.[__orig_rowid] = t1.[__orig_rowid]
JOIN [local_2].[crash_injury_summary] t2 ON t0.[__orig_rowid] = t2.[__orig_rowid]
JOIN [local_2].[crash_caltrans_segment] t3 ON t0.[__orig_rowid] = t3.[__orig_rowid]
JOIN [local_2].[crash_city_division_summary] t4 ON t0.[__orig_rowid] = t4.[__orig_rowid];

-- Reconstruct parties from vertical split + row partition on a fragment
CREATE VIEW "parties" AS
SELECT t0.[row_id], t0.[case_ref], t2.[pty_seq], t0.[pty_type], t0.[fault_ind], t0.[pty_sex], t0.[pty_age_yrs], t0.[pty_sobriety], t0.[drug_phys], t0.[dir_trav], t3.[safety_equip_primary], t3.[safety_equip_secondary], t0.[fin_resp], t0.[haz_mat], t3.[cp_inuse_ind], t3.[cp_use_type], t0.[sch_bus_flag], t4.[oaf_code], t4.[oaf_cat], t4.[oaf_sect_num], t4.[oaf_suffix], t4.[other_assoc_primary], t4.[other_assoc_alternate], t2.[pty_kill_cnt], t2.[pty_inj_cnt], t0.[mov_pre_coll], t0.[veh_year], t0.[veh_make], t1.[stwide_veh_type], t1.[chp_veh_towing], t1.[chp_veh_towed], t0.[pty_race]
FROM [local_3].[pty_fault] t0
JOIN [local_3].[pty_fault_tow] t1 ON t0.[__orig_rowid] = t1.[__orig_rowid]
JOIN [local_3].[case_pty_counts] t2 ON t0.[__orig_rowid] = t2.[__orig_rowid]
JOIN (
SELECT [cp_inuse_airbag_not_deployed].[__orig_rowid] AS __orig_rowid, [local_3].[cp_inuse_airbag_not_deployed].[row_id], [local_3].[cp_inuse_airbag_not_deployed].[drug_phys], [local_3].[cp_inuse_airbag_not_deployed].[safety_equip_primary], [local_3].[cp_inuse_airbag_not_deployed].[safety_equip_secondary], [local_3].[cp_inuse_airbag_not_deployed].[cp_inuse_ind], [local_3].[cp_inuse_airbag_not_deployed].[cp_use_type] FROM [local_3].[cp_inuse_airbag_not_deployed]
UNION
SELECT [cp_inuse_lap_shldr_harness].[__orig_rowid] AS __orig_rowid, [local_3].[cp_inuse_lap_shldr_harness].[row_id], [local_3].[cp_inuse_lap_shldr_harness].[drug_phys], [local_3].[cp_inuse_lap_shldr_harness].[safety_equip_primary], [local_3].[cp_inuse_lap_shldr_harness].[safety_equip_secondary], [local_3].[cp_inuse_lap_shldr_harness].[cp_inuse_ind], [local_3].[cp_inuse_lap_shldr_harness].[cp_use_type] FROM [local_3].[cp_inuse_lap_shldr_harness]
UNION
SELECT [cp_inuse_safety_other].[__orig_rowid] AS __orig_rowid, [local_3].[cp_inuse_safety_other].[row_id], [local_3].[cp_inuse_safety_other].[drug_phys], [local_3].[cp_inuse_safety_other].[safety_equip_primary], [local_3].[cp_inuse_safety_other].[safety_equip_secondary], [local_3].[cp_inuse_safety_other].[cp_inuse_ind], [local_3].[cp_inuse_safety_other].[cp_use_type] FROM [local_3].[cp_inuse_safety_other]
UNION
SELECT [cp_inuse_safety_varied].[__orig_rowid] AS __orig_rowid, [local_3].[cp_inuse_safety_varied].[row_id], [local_3].[cp_inuse_safety_varied].[drug_phys], [local_3].[cp_inuse_safety_varied].[safety_equip_primary], [local_3].[cp_inuse_safety_varied].[safety_equip_secondary], [local_3].[cp_inuse_safety_varied].[cp_inuse_ind], [local_3].[cp_inuse_safety_varied].[cp_use_type] FROM [local_3].[cp_inuse_safety_varied]
) t3 ON t0.[__orig_rowid] = t3.[__orig_rowid]
JOIN [local_3].[oaf_viol_meta] t4 ON t0.[__orig_rowid] = t4.[__orig_rowid];

-- Reconstruct victims from row partitions (UNION (overlap))
CREATE VIEW "victims" AS
SELECT "local_1"."VictimsAgeAtMost17"."VictimRecordId" AS "id", "local_1"."VictimsAgeAtMost17"."CaseIdentifier" AS "case_id", "local_1"."VictimsAgeAtMost17"."PartyPosition" AS "party_number", "local_1"."VictimsAgeAtMost17"."VictimRole" AS "victim_role", "local_1"."VictimsAgeAtMost17"."VictimSex" AS "victim_sex", "local_1"."VictimsAgeAtMost17"."VictimAge" AS "victim_age", "local_1"."VictimsAgeAtMost17"."InjurySeverity" AS "victim_degree_of_injury", "local_1"."VictimsAgeAtMost17"."SeatingPosition" AS "victim_seating_position", "local_1"."VictimsAgeAtMost17"."PrimarySafetyEquipment" AS "victim_safety_equipment_1", "local_1"."VictimsAgeAtMost17"."SecondarySafetyEquipment" AS "victim_safety_equipment_2", "local_1"."VictimsAgeAtMost17"."EjectionStatus" AS "victim_ejected" FROM "local_1"."VictimsAgeAtMost17"
UNION
SELECT "local_1"."VictimsAgeGreaterThan17UpTo27"."VictimRecordId" AS "id", "local_1"."VictimsAgeGreaterThan17UpTo27"."CaseIdentifier" AS "case_id", "local_1"."VictimsAgeGreaterThan17UpTo27"."PartyPosition" AS "party_number", "local_1"."VictimsAgeGreaterThan17UpTo27"."VictimRole" AS "victim_role", "local_1"."VictimsAgeGreaterThan17UpTo27"."VictimSex" AS "victim_sex", "local_1"."VictimsAgeGreaterThan17UpTo27"."VictimAge" AS "victim_age", "local_1"."VictimsAgeGreaterThan17UpTo27"."InjurySeverity" AS "victim_degree_of_injury", "local_1"."VictimsAgeGreaterThan17UpTo27"."SeatingPosition" AS "victim_seating_position", "local_1"."VictimsAgeGreaterThan17UpTo27"."PrimarySafetyEquipment" AS "victim_safety_equipment_1", "local_1"."VictimsAgeGreaterThan17UpTo27"."SecondarySafetyEquipment" AS "victim_safety_equipment_2", "local_1"."VictimsAgeGreaterThan17UpTo27"."EjectionStatus" AS "victim_ejected" FROM "local_1"."VictimsAgeGreaterThan17UpTo27"
UNION
SELECT "local_1"."VictimsAgeGreaterThan27UpTo44"."VictimRecordId" AS "id", "local_1"."VictimsAgeGreaterThan27UpTo44"."CaseIdentifier" AS "case_id", "local_1"."VictimsAgeGreaterThan27UpTo44"."PartyPosition" AS "party_number", "local_1"."VictimsAgeGreaterThan27UpTo44"."VictimRole" AS "victim_role", "local_1"."VictimsAgeGreaterThan27UpTo44"."VictimSex" AS "victim_sex", "local_1"."VictimsAgeGreaterThan27UpTo44"."VictimAge" AS "victim_age", "local_1"."VictimsAgeGreaterThan27UpTo44"."InjurySeverity" AS "victim_degree_of_injury", "local_1"."VictimsAgeGreaterThan27UpTo44"."SeatingPosition" AS "victim_seating_position", "local_1"."VictimsAgeGreaterThan27UpTo44"."PrimarySafetyEquipment" AS "victim_safety_equipment_1", "local_1"."VictimsAgeGreaterThan27UpTo44"."SecondarySafetyEquipment" AS "victim_safety_equipment_2", "local_1"."VictimsAgeGreaterThan27UpTo44"."EjectionStatus" AS "victim_ejected" FROM "local_1"."VictimsAgeGreaterThan27UpTo44"
UNION
SELECT "local_1"."VictimsAgeGreaterThan44OrUnknown"."VictimRecordId" AS "id", "local_1"."VictimsAgeGreaterThan44OrUnknown"."CaseIdentifier" AS "case_id", "local_1"."VictimsAgeGreaterThan44OrUnknown"."PartyPosition" AS "party_number", "local_1"."VictimsAgeGreaterThan44OrUnknown"."VictimRole" AS "victim_role", "local_1"."VictimsAgeGreaterThan44OrUnknown"."VictimSex" AS "victim_sex", "local_1"."VictimsAgeGreaterThan44OrUnknown"."VictimAge" AS "victim_age", "local_1"."VictimsAgeGreaterThan44OrUnknown"."InjurySeverity" AS "victim_degree_of_injury", "local_1"."VictimsAgeGreaterThan44OrUnknown"."SeatingPosition" AS "victim_seating_position", "local_1"."VictimsAgeGreaterThan44OrUnknown"."PrimarySafetyEquipment" AS "victim_safety_equipment_1", "local_1"."VictimsAgeGreaterThan44OrUnknown"."SecondarySafetyEquipment" AS "victim_safety_equipment_2", "local_1"."VictimsAgeGreaterThan44OrUnknown"."EjectionStatus" AS "victim_ejected" FROM "local_1"."VictimsAgeGreaterThan44OrUnknown";
